from __future__ import annotations

from pathlib import Path

from docx import Document
from docx.enum.text import WD_ALIGN_PARAGRAPH
from docx.oxml import OxmlElement
from docx.oxml.ns import qn
from docx.shared import Cm, Pt

OUT = Path('Отчет_курсовая_Наша_еда_30стр_компакт.docx')
MAX_PARAGRAPHS_PER_SECTION = 6


def set_font(run, size=14, bold=False):
    run.bold = bold
    run.font.name = 'Times New Roman'
    run.font.size = Pt(size)
    run._element.rPr.rFonts.set(qn('w:eastAsia'), 'Times New Roman')


def configure(doc: Document):
    sec = doc.sections[0]
    sec.top_margin = Cm(2)
    sec.right_margin = Cm(1)
    sec.bottom_margin = Cm(2)
    sec.left_margin = Cm(2)
    sec.different_first_page_header_footer = True

    st = doc.styles['Normal']
    st.font.name = 'Times New Roman'
    st.font.size = Pt(14)
    st._element.rPr.rFonts.set(qn('w:eastAsia'), 'Times New Roman')
    st.paragraph_format.alignment = WD_ALIGN_PARAGRAPH.JUSTIFY
    st.paragraph_format.line_spacing = 1.5
    st.paragraph_format.first_line_indent = Cm(1.25)
    st.paragraph_format.space_before = Pt(0)
    st.paragraph_format.space_after = Pt(0)


def add_page_number(p):
    p.alignment = WD_ALIGN_PARAGRAPH.CENTER
    p.paragraph_format.first_line_indent = Cm(0)
    run = p.add_run()
    set_font(run, size=12)
    b = OxmlElement('w:fldChar')
    b.set(qn('w:fldCharType'), 'begin')
    i = OxmlElement('w:instrText')
    i.set(qn('xml:space'), 'preserve')
    i.text = ' PAGE '
    s = OxmlElement('w:fldChar')
    s.set(qn('w:fldCharType'), 'separate')
    t = OxmlElement('w:t')
    t.text = '1'
    e = OxmlElement('w:fldChar')
    e.set(qn('w:fldCharType'), 'end')
    run._r.extend([b, i, s, t, e])


def add_heading(doc: Document, text: str, size=16):
    p = doc.add_paragraph()
    p.alignment = WD_ALIGN_PARAGRAPH.CENTER
    p.paragraph_format.first_line_indent = Cm(0)
    p.paragraph_format.line_spacing = 1.5
    r = p.add_run(text)
    set_font(r, size=size, bold=True)


def add_body(doc: Document, text: str):
    p = doc.add_paragraph(text)
    p.alignment = WD_ALIGN_PARAGRAPH.JUSTIFY
    p.paragraph_format.first_line_indent = Cm(1.25)
    p.paragraph_format.line_spacing = 1.5
    p.paragraph_format.space_before = Pt(0)
    p.paragraph_format.space_after = Pt(0)
    for r in p.runs:
        set_font(r, size=14)


def add_center(doc: Document, text: str, size=14, bold=False):
    p = doc.add_paragraph()
    p.alignment = WD_ALIGN_PARAGRAPH.CENTER
    p.paragraph_format.first_line_indent = Cm(0)
    r = p.add_run(text)
    set_font(r, size=size, bold=bold)


def add_right(doc: Document, text: str):
    p = doc.add_paragraph()
    p.alignment = WD_ALIGN_PARAGRAPH.RIGHT
    p.paragraph_format.first_line_indent = Cm(0)
    r = p.add_run(text)
    set_font(r, size=14)


def blank(doc: Document, n=1):
    for _ in range(n):
        add_body(doc, '')


def add_title(doc: Document):
    add_center(doc, 'БПОУ УР «Ижевский индустриальный техникум имени Е. Ф. Драгунова»')
    add_center(doc, 'Цикловая комиссия информационных технологий')
    blank(doc, 4)
    add_center(doc, 'КУРСОВАЯ РАБОТА', size=16, bold=True)
    add_center(doc, 'по профессиональному модулю ПМ.09', bold=True)
    add_center(doc, '«Проектирование, разработка и оптимизация веб-приложений»', bold=True)
    blank(doc, 2)
    add_center(doc, 'Тема: Разработка веб-приложения «Наша Еда»', bold=True)
    blank(doc, 6)
    add_right(doc, 'Выполнил: студент группы __________')
    add_right(doc, 'специальности 09.02.07 «Информационные системы и программирование»')
    add_right(doc, '____________________________________')
    blank(doc, 2)
    add_right(doc, 'Руководитель: ________________________')
    blank(doc, 8)
    add_center(doc, 'Ижевск, 2026')


def add_contents(doc: Document):
    doc.add_page_break()
    add_heading(doc, 'СОДЕРЖАНИЕ')
    for line in [
        'Введение .............................................................................................. 3',
        '1. Теоретические основы проектирования веб-приложения .................................... 4',
        '2. Проектирование и разработка сайта «Наша Еда» .......................................... 10',
        '3. Развертывание и публикация на хостинге .................................................. 18',
        'Заключение ............................................................................................ 24',
        'Список использованных источников .......................................................... 25',
        'Приложения .......................................................................................... 26',
    ]:
        add_body(doc, line)


